VALUES
  ('dietitian-moex-09194', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '拓樸異構酶（topoisomerase）可以打斷與重新接合去氧核糖核酸雙股，並每次改變兩個交聯數（linking number）的是屬於那一型？', '["第一型（type I）", "第二型（type II）", "第一型與第二型皆會", "第一型與第二型皆只會打斷去氧核糖核酸的一股，並改變一個交聯數"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 29, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09195', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '真核細胞（eukaryotic cell）具有五種去氧核糖核酸聚合酶（DNA polymerase），何種存在粒線體內，負 責粒線體去氧核糖核酸的複製（DNA replication）和修復（DNA repair）？', '["α", "β", "γ", "δ"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09196', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '原血色素（heme）來自於血紅素（hemoglobin）或細胞色素（cytochromes），經過降解後，會變成下列 何者進入膽汁（bile）？', '["膽綠素（biliverdin）", "膽紅素（bilirubin）", "膽紅素二葡萄糖醛酸苷（bilirubin diglucuronide）", "膽紅素白蛋白（bilirubin albumin）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09197', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '胺甲蝶呤（methotrexate）是抑制二氫葉酸還原酶（dihydrofolate reductase）的葉酸拮抗劑，為白血病 （leukemia）的治療藥，這屬於何種酵素抑制反應？', '["競爭型抑制（competitive inhibition）", "非競爭型抑制（noncompetitive inhibition）", "綜合型抑制（mixed inhibition）", "不可逆抑制（irreversible inhibition）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09198', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '解偶聯劑（uncoupler）抑制電子傳遞鏈（electron transport chain）中ATP的合成，是經由傳送氫離子回到 基質（matrix）的機制；那麼，寡黴素（oligomycin）是利用下列那一種機制抑制ATP的合成？', '["與解偶聯劑2,4-dinitrophenol（DNP）相同", "與纈胺黴素（valinomycin）相同，為一脂溶性離子載體（ionophore）", "與尼日利亞菌素（nigericin）相同，為一K+/H+離子載體", "結合ATP合成酶的F，抑制氫離子的通透 0"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09199', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '果糖-2,6-二磷酸（fructose-2,6-bisphosphate）在肝細胞內的濃度決定細胞是進行糖質新生作用 （gluconeogenesis）或糖解作用（glycolysis）。當血糖下降時，昇糖激素（glucagon）會促進下列何者的 作用而影響其濃度？', '["cAMP的濃度上昇", "磷酸果糖激酶-2（phosphofructokinase-2）的活性增加", "磷酸果糖激酶-1（phosphofructokinase-1）的活性增加", "果糖-2,6-二磷酸酶（fructose-2,6-bisphosphatase）的活性下降"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09200', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '檸檬酸（citrate）經三羧酸輸送載體（tricarboxylate transporter）送出粒線體後，在細胞質再經由下列那一 種酵素分解而成乙醯輔酶A（acetyl-CoA）後，可當作合成脂肪酸的原料？', '["酮醯基輔酶A合成酶（3-ketoacyl-CoA-synthase）", "腺苷三磷酸-檸檬酸分解酶（ATP-citrate lyase）", "檸檬酸合成酶（citrate synthase）", "檸檬酸去氫酶（citrate dehydrogenase）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09201', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '若細胞要進行脂肪酸的生合成，葡萄糖-6-磷酸（glucose-6-phosphate）需要選擇那些代謝途徑，以供 應之？', '["糖解作用（glycolysis）＋五碳糖磷酸鹽途徑（pentose phosphate pathway）", "五碳糖磷酸鹽途徑＋糖質新生作用（gluconeogenesis）", "糖質新生作用＋肝醣分解（glycogenolysis）", "肝醣分解＋糖解作用"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09202', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '下列何者是高能磷酸化合物（high energy phosphate compound），在糖解作用（glycolysis）中會進行受 質層次的磷酸化作用（substrate level phosphorylation）？', '["2,3-二磷酸甘油酸（2,3-bisphosphoglycerate）", "乙醯輔酶A（acetyl-CoA）", "磷酸烯醇丙酮酸（phosphoenolpyruvate）", "葡萄糖-6-磷酸（glucose-6-phosphate）"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL),
  ('dietitian-moex-09203', 'dietitian', 'dietitian-moex-097-629fe76c', 'sub-dietitian-04', NULL, 'single_choice', '中間代謝（intermediary metabolism）是指所有代謝途徑中，低分子量的前驅物（precursors）、代謝物 （metabolites）和產物（products）之間，互相轉換的活動總和。所指低分子量約為多少道爾頓（dalton）？', '["5至10 kDa", "1至5 kDa", "低於1 kDa", "10至100 kDa"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:11:52+00:00", "source_pdf_sha1": "f0be3dbf80f4", "answer_pdf_sha1": "7e47bc9a0ee3", "source_family": "moex-gov-tw", "moex": {"exam_code": "097050", "c": "113", "s": "1001", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "生理學與生物化學", "year": "097", "exam_name": "097年第一次專技高普考醫事人員、中醫師、心理師、營養師、獸醫佐考試暨醫師分試考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "dietitian", "db_exam_id": "dietitian"}'::jsonb, NULL)
